mapper.update:
update users
set
    email = #{email},
    nickname = case
        when nickname_confirmed = true then nickname
        else #{nickname}
    end,
    nickname_normalized = case
        when nickname_confirmed = true then nickname_normalized
        else #{nicknameNormalized}
    end,
    status = 'ACTIVE',
    google_subject = #{googleSubject},
    profile_image_url = #{profileImageUrl},
    last_login_at = #{lastLoginAt}
where id = #{userId}

mapper.select:
select exists(
    select 1
    from users
    where nickname_normalized = #{nicknameNormalized}
      and id != #{userId}
      and status = 'ACTIVE'
)
